const PI = 3.141592653589793;
const SOLAR_MASS = 4.0 * PI * PI;
const DAYS_PER_YEAR = 365.24;

const bodies = [
    { x:0, y:0, z:0, vx:0, vy:0, vz:0, mass:SOLAR_MASS },
    { x:4.84143144246472090e+00, y:-1.16032004402742839e+00, z:-1.03622044471123109e-01,
      vx:1.66007664274403694e-03*DAYS_PER_YEAR, vy:7.69901118419740425e-03*DAYS_PER_YEAR,
      vz:-6.90460016972063023e-05*DAYS_PER_YEAR, mass:9.54791938424326609e-04*SOLAR_MASS },
    { x:8.34336671824457987e+00, y:4.12479856412430479e+00, z:-4.03523417114321381e-01,
      vx:-2.76742510726862411e-03*DAYS_PER_YEAR, vy:4.99852801234917238e-03*DAYS_PER_YEAR,
      vz:2.30417297573763929e-05*DAYS_PER_YEAR, mass:2.85885980666130812e-04*SOLAR_MASS },
    { x:1.28943695621391310e+01, y:-1.51111514016986312e+01, z:-2.23307578892655734e-01,
      vx:2.96460137564761618e-03*DAYS_PER_YEAR, vy:2.37847173959480950e-03*DAYS_PER_YEAR,
      vz:-2.96589568540237556e-05*DAYS_PER_YEAR, mass:4.36624404335156298e-05*SOLAR_MASS },
    { x:1.53796971148509165e+01, y:-2.59193146099879641e+01, z:1.79258772950371181e-01,
      vx:2.68067772490389322e-03*DAYS_PER_YEAR, vy:1.62824170038242295e-03*DAYS_PER_YEAR,
      vz:-9.51592254519715870e-05*DAYS_PER_YEAR, mass:5.15138902046611451e-05*SOLAR_MASS }
];

function offsetMomentum() {
    let px=0, py=0, pz=0;
    for (let i=0; i<5; i++) { px+=bodies[i].vx*bodies[i].mass; py+=bodies[i].vy*bodies[i].mass; pz+=bodies[i].vz*bodies[i].mass; }
    bodies[0].vx=-px/SOLAR_MASS; bodies[0].vy=-py/SOLAR_MASS; bodies[0].vz=-pz/SOLAR_MASS;
}

function energy() {
    let e=0;
    for (let i=0; i<5; i++) {
        e += 0.5*bodies[i].mass*(bodies[i].vx*bodies[i].vx+bodies[i].vy*bodies[i].vy+bodies[i].vz*bodies[i].vz);
        for (let j=i+1; j<5; j++) {
            const dx=bodies[i].x-bodies[j].x, dy=bodies[i].y-bodies[j].y, dz=bodies[i].z-bodies[j].z;
            e -= bodies[i].mass*bodies[j].mass/Math.sqrt(dx*dx+dy*dy+dz*dz);
        }
    }
    return e;
}

function advance(dt) {
    for (let i=0; i<5; i++) {
        for (let j=i+1; j<5; j++) {
            const dx=bodies[i].x-bodies[j].x, dy=bodies[i].y-bodies[j].y, dz=bodies[i].z-bodies[j].z;
            const dist=Math.sqrt(dx*dx+dy*dy+dz*dz);
            const mag=dt/(dist*dist*dist);
            bodies[i].vx-=dx*bodies[j].mass*mag; bodies[i].vy-=dy*bodies[j].mass*mag; bodies[i].vz-=dz*bodies[j].mass*mag;
            bodies[j].vx+=dx*bodies[i].mass*mag; bodies[j].vy+=dy*bodies[i].mass*mag; bodies[j].vz+=dz*bodies[i].mass*mag;
        }
    }
    for (let i=0; i<5; i++) { bodies[i].x+=dt*bodies[i].vx; bodies[i].y+=dt*bodies[i].vy; bodies[i].z+=dt*bodies[i].vz; }
}

const n = parseInt(process.argv[2]);
offsetMomentum();
console.log(energy().toFixed(9));
for (let i=0; i<n; i++) advance(0.01);
console.log(energy().toFixed(9));

const n = parseInt(process.argv[2]);
let count = 0;
for (let y = 0; y < n; y++) for (let x = 0; x < n; x++) {
    const cr = 2*x/n - 1.5, ci = 2*y/n - 1;
    let zr = 0, zi = 0, inside = true;
    for (let i = 0; i < 50; i++) {
        const t = zr*zr - zi*zi + cr; zi = 2*zr*zi + ci; zr = t;
        if (zr*zr + zi*zi > 4) { inside = false; break; }
    }
    if (inside) count++;
}
console.log(count);

function A(i,j){return 1/((i+j)*(i+j+1)/2+i+1)}
function mulAv(n,v,r){for(let i=0;i<n;i++){r[i]=0;for(let j=0;j<n;j++)r[i]+=A(i,j)*v[j]}}
function mulAtv(n,v,r){for(let i=0;i<n;i++){r[i]=0;for(let j=0;j<n;j++)r[i]+=A(j,i)*v[j]}}
function mulAtAv(n,v,r,t){mulAv(n,v,t);mulAtv(n,t,r)}
const n=parseInt(process.argv[2]);
const u=new Float64Array(n).fill(1),v=new Float64Array(n),t=new Float64Array(n);
for(let i=0;i<10;i++){mulAtAv(n,u,v,t);mulAtAv(n,v,u,t)}
let vBv=0,vv=0;
for(let i=0;i<n;i++){vBv+=u[i]*v[i];vv+=v[i]*v[i]}
console.log(Math.sqrt(vBv/vv).toFixed(9));

